    @NotNull
    private static DeferredHolder<SoundEvent, SoundEvent> registerSound(@NotNull String name) {
        ResourceLocation resourceLocation = BFRes.loc(name);
        DeferredHolder deferredHolder = DR.register(resourceLocation.getPath(), () -> SoundEvent.createVariableRangeEvent((ResourceLocation)resourceLocation));
        BY_ID.put((Object)resourceLocation.toString(), (Object)deferredHolder);
        return deferredHolder;
    }

    @Nullable
    public static SoundEvent retrieve(@NotNull String id) {
        for (DeferredHolder deferredHolder : BY_ID.values()) {
            String string;
            ResourceLocation resourceLocation = BuiltInRegistries.SOUND_EVENT.getKey((Object)((SoundEvent)deferredHolder.get()));
            if (resourceLocation == null || !(string = resourceLocation.toString()).equals(id) && !string.equals("bf:" + id)) continue;
            return Optional.of(deferredHolder).map(DeferredHolder::get).orElse(null);
        }
        return null;
    }

    @Nullable
    public static String getId(@NotNull SoundEvent soundEvent) {
        for (Map.Entry entry : BY_ID.entrySet()) {
            if (((DeferredHolder)entry.getValue()).get() != soundEvent) continue;
            return Optional.of(entry).map(Map.Entry::getKey).orElse(null);
        }
        return null;
    }

